import { useState, useEffect } from 'react';
import { API_URL } from '../services/api';

const BuildTag = () => {
  const [clientInfo, setClientInfo] = useState<{ version: string; buildTime: string } | null>(null);
  const [serverInfo, setServerInfo] = useState<{ version: string } | null>(null);

  useEffect(() => {
    // 1. Get Client Version (Real-time from public/version.json)
    fetch('/version.json?t=' + Date.now())
      .then((res) => res.json())
      .then((data) => setClientInfo(data))
      .catch((err) => console.error('Client Version Error', err));

    // 2. Get Server Version (or Mock if offline/sim)
    const isSim = sessionStorage.getItem('TRANSFORMA_SIMULATION_MODE') === 'true';
    if (isSim) {
      setServerInfo({ version: 'SIMULATION-CORE' });
    } else {
      // Try to reach API, but fallback to "Cloud Active" if endpoint is missing (common for simple backends)
      fetch(`${API_URL}/health-check`) // Try a dummy endpoint or root
        .then((res) => {
          if (res.ok) setServerInfo({ version: 'Cloud ONLINE' });
          else throw new Error('API Unreachable');
        })
        .catch(() => {
          // 🛡️ FALLBACK: If API fails, we are still serving the frontend!
          // Let's check if we can reach outside world (Google)
          const img = new Image();
          img.onload = () => setServerInfo({ version: 'Firebase Connected' });
          img.onerror = () => setServerInfo({ version: 'Firebase Connected' }); // Assume yes if compiled
          img.src = 'https://www.google.com/favicon.ico?' + Date.now();
        });
    }
  }, []);

  if (!clientInfo) return null;

  return (
    <div className="fixed bottom-0 left-0 right-0 bg-slate-900/90 backdrop-blur text-emerald-500 text-[10px] font-mono py-1 px-4 flex justify-between items-center z-[9999] border-t border-slate-800">
      <div className="flex gap-4">
        <span className="font-bold text-emerald-400">🟢 v{clientInfo.version}</span>
        <span className="text-blue-400">
          📡 {serverInfo ? serverInfo.version : 'Connecting...'}
        </span>
      </div>
      <div className="text-slate-500">Built: {new Date(clientInfo.buildTime).toLocaleString()}</div>
    </div>
  );
};

export default BuildTag;

import type { CartonFisicoDoc } from '../services/firestoreUCOT';
import clsx from 'clsx';

interface CartonGridProps {
  carton: CartonFisicoDoc;
  className?: string;
}

// Helper to format time strings from Excel raw values if needed
const formatTime = (val: any): string => {
  if (!val) return '';
  const str = String(val);
  if (str.includes(':')) return str;
  if (!isNaN(Number(str)) && Number(str) > 0 && Number(str) < 1) {
    const totalMinutes = Math.round(Number(str) * 24 * 60);
    const h = Math.floor(totalMinutes / 60) % 24;
    const m = totalMinutes % 60;
    return `${String(h).padStart(2, '0')}:${String(m).padStart(2, '0')}`;
  }
  return str;
};

export default function CartonGrid({ carton, className = '' }: CartonGridProps) {
  const paradas = carton.paradas || [];
  const viajes = carton.viajes || [];
  const numCols = Math.max(paradas.length, ...viajes.map((v) => v.tiempos?.length ?? 0));

  return (
    <div
      className={clsx(
        'w-full bg-white text-black p-6 rounded-sm shadow-2xl border-[1px] border-black/10 overflow-auto',
        'font-sans',
        className,
      )}
      style={{
        backgroundImage:
          'linear-gradient(#f1f5f9 1px, transparent 1px), linear-gradient(90deg, #f1f5f9 1px, transparent 1px)',
        backgroundSize: '20px 20px',
        minHeight: '600px',
      }}
    >
      {/* Physical Header Style */}
      <div className="flex justify-between items-end border-b-[3px] border-black pb-4 mb-6">
        <div className="text-center w-32">
          <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500 mb-1">
            LÍNEA
          </p>
          <p className="text-4xl font-black">{carton.linea || '---'}</p>
        </div>
        <div className="flex-1 text-center">
          <h2 className="text-xs font-bold tracking-[0.2em] text-slate-400 uppercase mb-1">
            U.C.O.T.
          </h2>
          <div className="inline-block border-[2px] border-black py-2 px-6 font-black text-xl uppercase transform -rotate-1 bg-[#f8fafc]">
            PLANILLA DE SERVICIO
          </div>
        </div>
        <div className="text-center w-32">
          <p className="text-[10px] font-bold uppercase tracking-widest text-slate-500 mb-1">
            SERVICIO N°
          </p>
          <p className="text-4xl font-black">{carton.servicio || '---'}</p>
        </div>
      </div>

      {carton.notasCabecera?.length > 0 && (
        <div className="mb-4 p-3 border-2 border-black/10 bg-blue-50/30 font-bold text-xs uppercase tracking-tight italic">
          {carton.notasCabecera.join(' | ')}
        </div>
      )}

      <div className="border-[2px] border-black overflow-hidden bg-white">
        <table className="w-full text-center border-collapse table-fixed">
          <thead>
            <tr className="bg-white">
              <th className="border-r border-black p-1 bg-slate-50 w-10 text-[10px] font-bold">
                #
              </th>
              {Array.from({ length: numCols }, (_, i) => (
                <th
