            🎉 ¡SUBIDA EXITOSA!
          </p>
          <a
            href={imageUrl}
            target="_blank"
            rel="noreferrer"
            style={{ fontSize: '0.8em', color: '#1565c0', wordBreak: 'break-all' }}
