                ...c,
                name: editFormData.name,
                baseValue: editFormData.baseValue,
                extraHourValue: editFormData.extraHourValue,
              }
            : c,
        ),
      );

      setEditingCategory(null); // Close modal
      alert('Cambios guardados correctamente');
