                onClick={executeConfirmAction}
                className="flex-1 py-2.5 rounded-xl bg-red-600 hover:bg-red-700 text-white shadow-lg shadow-red-900/20 transition-all font-bold"
              >
                <span>{confirmAction.type === 'reject' ? 'Sí, Rechazar' : 'Sí, Eliminar'}</span>
              </button>
            </div>
          </div>
        </div>
      )}

      <div className="border-b border-slate-800 flex gap-4 overflow-x-auto pb-2 custom-scrollbar">
        <TabButton
          name="Created"
          label="Pendientes"
          count={shifts.filter((s) => s.status === 'Created').length}
        />
        <TabButton
          name="Public"
          label="Públicos"
          count={shifts.filter((s) => s.status === 'Public').length}
        />
        <TabButton
          name="Assigned"
          label="Asignados"
          count={shifts.filter((s) => s.status === 'Assigned').length}
        />
      </div>

      {/* Content */}
      {error && (
        <div className="bg-red-500/10 border border-red-500/50 rounded-xl p-4 mb-6 flex items-center gap-3 animate-fade-in">
          <AlertCircle className="w-6 h-6 text-red-400" />
          <div className="flex-1">
            <h3 className="text-red-400 font-bold text-sm">Error de Conexión</h3>
            <p className="text-red-300/80 text-sm">{error}</p>
          </div>
          <button
            onClick={loadShifts}
            className="px-3 py-1.5 bg-red-500/20 hover:bg-red-500/30 text-red-300 rounded-lg text-xs font-bold transition-colors"
          >
            Reintentar
          </button>
        </div>
      )}

      {isLoading ? (
        <div className="py-20 flex flex-col items-center justify-center text-slate-500 animate-fade-in">
          <Loader2 className="w-10 h-10 text-primary-500 animate-spin mb-4" />
          <span className="text-sm font-medium text-slate-400 animate-pulse">
            Cargando turnos en tiempo real...
          </span>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {filteredShifts.length > 0 ? (
            filteredShifts.map((shift) => (
              <ShiftCard key={shift.id} shift={shift} variant="admin" onAction={handleAction} />
            ))
          ) : (
            <div className="col-span-full py-20 flex flex-col items-center justify-center text-slate-500 border border-dashed border-slate-800 rounded-2xl bg-slate-900/50">
              <div className="w-12 h-12 bg-slate-800 rounded-full flex items-center justify-center mb-4 text-slate-600">
                <Filter className="w-6 h-6" />
              </div>
              <p>
                <span>No hay turnos en esta categoría</span>
              </p>
            </div>
          )}
        </div>
      )}

      {/* Edit Modal */}
      {editingShift && (
        <EditShiftModal
          shift={editingShift}
          onClose={() => setEditingShift(null)}
          onSave={() => {
            loadShifts();
            setEditingShift(null);
          }}
        />
      )}

      {/* Assign Modal */}
      {assigningShiftId && (
        <AssignShiftModal
          onClose={() => setAssigningShiftId(null)}
          onAssign={handleAssignShift}
          currentAssigneeId={
            Number(shifts.find((s) => s.id === assigningShiftId)?.assignedTo ?? 0) as number
          }
        />
      )}
    </div>
  );
};

