          {/* Alert Markers */}
          {alerts.map((alert: any) => (
            <CircleMarker
              key={alert.id}
              center={[alert.lat, alert.lng]}
              radius={10}
              color="#ef4444"
              fillColor="#ef4444"
              fillOpacity={0.6}
