    setStmResult(null);
    setStmUploading(true);
    try {
      let text: string;
      const isZip = file.name.toLowerCase().endsWith('.zip');
      if (isZip) {
        const buffer = await file.arrayBuffer();
        const geojson = await shp(buffer);
        const normalized = Array.isArray(geojson)
          ? {
              type: 'FeatureCollection' as const,
              features: geojson.flatMap((g: { type?: string; features?: unknown[] }) =>
                g?.type === 'FeatureCollection' && g.features ? g.features : [g],
              ),
            }
          : (geojson as { type?: string; features?: unknown[] })?.type === 'FeatureCollection'
            ? geojson
            : { type: 'FeatureCollection' as const, features: [geojson] };
        text = JSON.stringify(normalized);
      } else {
        text = await file.text();
      }
      const lineas = parseGeoJSONOrJSONToLineasUCOT(text);
      if (lineas.length === 0) {
        toast.error(
          'No se encontraron líneas en el archivo. Esperado: { lineas: [...] } o GeoJSON FeatureCollection.',
        );
        setStmUploading(false);
        return;
      }
      const result = await writeLineasUCOTInBatches(lineas, (written, total) => {
        setStmProgress({ written, total });
      });
      setStmProgress(null);
      setStmResult(result);
      if (result.errors.length === 0)
        toast.success(`${result.written} recorridos STM guardados en lineas_ucot.`);
      else toast.error(`${result.written} OK, ${result.errors.length} errores.`);
    } catch (e) {
      toast.error('Error al procesar archivo: ' + (e instanceof Error ? e.message : String(e)));
      setStmProgress(null);
      setStmResult(null);
    } finally {
      setStmUploading(false);
    }
  }, []);

  // 🚀 CLIENT-SIDE PROCESSING
  const analyzeFile = async (uploadedFile: File) => {
    setUploading(true);
    try {
      // 1. Parse Excel in Browser
      const result = await ExcelParser.parse(uploadedFile);
      setParsedData(result);

      // 2. Análisis local: se ingestarán TODOS los servicios (sin límite)
      const total = result.services.length;
      setAnalysis({
        type: 'JSON_READY',
        count: total,
        preview: result.services.slice(0, 50), // Solo vista previa (máx 50 filas en tabla)
        message: `Archivo procesado: ${result.lines.length} Líneas, ${total} Servicios. Se ingestarán los ${total} registros en la nube.`,
      });
    } catch (error) {
      console.error(error);
      setAnalysis({
        type: 'UNKNOWN',
        count: 0,
        preview: [],
        message: 'Error al procesar archivo en navegador: ' + (error as any).message,
      });
    } finally {
      setUploading(false);
    }
  };

  const [importMode, setImportMode] = useState<'AUTO' | 'ROTATION' | 'CARTON'>('AUTO');
  const [selectedDate, setSelectedDate] = useState<string>(new Date().toISOString().split('T')[0]);

  // ...

  const confirmUpload = async () => {
    if (!parsedData) return;
    setUploading(true);

    try {
      // 1. CLOUD PUBLISH (If checked)
      if (publishToCloud && file) {
        const toastId = toast.loading('Subiendo archivo oficial a Nube...');
        try {
          const timestamp = Date.now();
          const storagePath = `service_matrices/${uploadArea}/${timestamp}_${file.name}`;
          const storageRef = ref(storage, storagePath);

          await uploadBytes(storageRef, file);
          const downloadURL = await getDownloadURL(storageRef);

          // Metadata
          await addDoc(collection(db, 'service_matrices'), {
            fileName: file.name,
            fileUrl: downloadURL,
            area: uploadArea,
            uploadedAt: serverTimestamp(),
            uploadedBy: 'Admin',
            size: file.size,
            type: 'OFFICIAL_MATRIX',
          });
          toast.success('Archivo publicado correctamente', { id: toastId });
        } catch (e: any) {
          toast.error('Error al subir archivo a nube: ' + e.message, { id: toastId });
          // We continue to Ingestion even if Cloud Upload fails?
          // Let's stop if critical? No, allow Partial success.
        }
      }

      // 2. DATA INGESTION (Firestore Seeding)
      const { TransitSeeder } = await import('../../services/TransitSeeder'); // Lazy load

      let res;
      if (importMode === 'ROTATION') {
        res = await TransitSeeder.importUniversal(
          { ...parsedData, type: 'ROTACION' },
          selectedDate,
        );
      } else {
        res = await TransitSeeder.importUniversal(parsedData, selectedDate);
      }

      if (res.success) {
        setSuccessMsg(res.message + (publishToCloud ? ' + Publicado en Nube' : ''));
        setAnalysis(null);
        setFile(null);
        setParsedData(null);
      } else {
        alert('Error de Ingesta: ' + res.message);
      }
    } catch (error) {
      console.error(error);
      alert('Error crítico de subida: ' + (error as any).message);
    } finally {
      setUploading(false);
    }
  };

  const downloadReport = () => {
    const token = localStorage.getItem('token');
    fetch(`${API_URL}/simulation/report`, {
      headers: { Authorization: `Bearer ${token}` },
    })
      .then((res) => res.blob())
      .then((blob) => {
        const url = window.URL.createObjectURL(blob);
        const a = document.createElement('a');
        a.href = url;
        a.download = 'Simulacion_Operativa.pdf';
        document.body.appendChild(a);
        a.click();
        a.remove();
      })
      .catch((e) => alert('Error descargando reporte'));
  };

  const resetSimulation = async () => {
    if (!confirm('¿Estás seguro? Esto borrará todas las alertas de simulación activas.')) return;
    try {
      const token = localStorage.getItem('token');
      await fetch(`${API_URL}/simulation/reset`, {
        method: 'POST',
        headers: { Authorization: `Bearer ${token}` },
      });
      alert('Simulación reiniciada correctamente.');
    } catch (e) {
      console.error(e);
      alert('Error al reiniciar.');
    }
  };

  return (
    <div className="p-8 max-w-4xl mx-auto space-y-8 animate-in fade-in">
      <div className="text-center space-y-2">
        <h1 className="text-4xl font-black text-white tracking-tight flex items-center justify-center gap-3">
          <FileSpreadsheet className="w-10 h-10 text-emerald-400" />
          Ingesta Universal V3.0 (Cloud + Data)
        </h1>
        <p className="text-slate-400 text-lg">
          Soporta: Matriz (300a), Rotación (Coches), y Sábana (Horarios).
        </p>
        <div className="pt-4">
          <button
            onClick={async () => {
              const token = localStorage.getItem('token');
              const res = await fetch(`${API_URL}/data-import/template`, {
                headers: { Authorization: `Bearer ${token}` },
              });
              if (!res.ok) return alert('Error al descargar plantilla');
              const blob = await res.blob();
              const url = window.URL.createObjectURL(blob);
              const a = document.createElement('a');
              a.href = url;
              a.download = 'Plantilla_Servicios_V2026.xlsx';
              a.click();
            }}
            className="text-sm font-bold text-emerald-400 underline hover:text-emerald-300 flex items-center justify-center gap-2"
          >
            <Download className="w-4 h-4" />
            DESCARGAR PLANTILLA OFICIAL (.XLSX)
          </button>
          <p className="text-xs text-slate-500 mt-1">
            Usa esta plantilla para evitar errores de columnas faltantes.
          </p>
        </div>
      </div>

      {/* Sincronizar Líneas UCOT (Navegador) — 12.7 */}
      <div className="bg-slate-800/80 rounded-2xl border border-slate-700 p-6 mb-6">
        <h3 className="text-lg font-bold text-white flex items-center gap-2">
          <Map className="w-5 h-5 text-primary-500" />
          Sincronizar Líneas UCOT
        </h3>
        <p className="text-slate-400 text-sm mt-1 mb-4">
          Pre-carga recorridos y paradas desde la API de Montevideo para el Navegador UCOT. Una vez
          sincronizadas, estarán disponibles offline en Firestore.
        </p>
        <button
          type="button"
          onClick={handleSyncLineasUCOT}
          disabled={!!syncProgress}
          className="flex items-center gap-2 px-4 py-3 rounded-xl bg-primary-600 hover:bg-primary-500 text-white font-medium disabled:opacity-50"
        >
          {syncProgress ? (
            <>
              <Loader2 className="w-5 h-5 animate-spin" />
              {syncProgress.current} / {syncProgress.total} — {syncProgress.codigo}
            </>
          ) : (
            <>
              <Cloud className="w-5 h-5" />
              Sincronizar todas las líneas UCOT
            </>
          )}
        </button>
        {syncProgress && (
          <div className="mt-3 h-2 bg-slate-700 rounded-full overflow-hidden">
            <div
              className="h-full bg-primary-500 transition-all duration-300"
              style={{ width: `${(syncProgress.current / syncProgress.total) * 100}%` }}
            />
          </div>
        )}
        {syncResult && !syncProgress && (
          <div className="mt-3 text-sm text-slate-300">
            <span className="text-emerald-400 font-medium">
              {syncResult.synced} líneas sincronizadas.
            </span>
            {syncResult.errors.length > 0 && (
              <p className="text-amber-400 mt-1">Errores: {syncResult.errors.join('; ')}</p>
            )}
          </div>
        )}
      </div>

      {/* Ingesta de Recorridos STM (GeoJSON/JSON) — Plan B Datos Abiertos IMM */}
      <div className="bg-slate-800/80 rounded-2xl border border-slate-700 p-6 mb-6">
        <h3 className="text-lg font-bold text-white flex items-center gap-2">
          <Map className="w-5 h-5 text-amber-500" />
          Ingesta de Recorridos STM (GeoJSON/JSON)
        </h3>
        <p className="text-slate-400 text-sm mt-1 mb-4">
          Sube un archivo .json o .geojson de Datos Abiertos de la IMM. Formato:{' '}
          <code className="text-amber-400 bg-slate-900 px-1 rounded">
            {'{ lineas: [ { codigo, nombre?, paradas?, recorrido? } ] }'}
          </code>{' '}
          o GeoJSON FeatureCollection con LineString.
        </p>
        <div className="flex flex-wrap items-center gap-4">
          <label className="flex items-center gap-2 px-4 py-3 rounded-xl bg-slate-700 hover:bg-slate-600 text-white font-medium cursor-pointer transition-colors">
            <FileUp className="w-5 h-5" />
            <span>Seleccionar archivo .json / .geojson / .zip (Shapefile)</span>
            <input
              type="file"
              accept=".json,.geojson,.zip,application/json,application/zip"
              className="hidden"
              disabled={!!stmUploading}
              onChange={(e) => {
                const f = e.target.files?.[0];
                if (f) handleStmFileUpload(f);
                e.target.value = '';
              }}
            />
          </label>
          {stmUploading && (
            <div className="flex items-center gap-2 text-amber-400">
              <Loader2 className="w-5 h-5 animate-spin" />
              {stmProgress ? `${stmProgress.written} / ${stmProgress.total}` : 'Procesando...'}
            </div>
          )}
        </div>
        {stmProgress && (
          <div className="mt-3 h-2 bg-slate-700 rounded-full overflow-hidden">
            <div
              className="h-full bg-amber-500 transition-all duration-300"
              style={{ width: `${(stmProgress.written / stmProgress.total) * 100}%` }}
            />
          </div>
        )}
        {stmResult && !stmUploading && (
          <div className="mt-3 text-sm text-slate-300">
            <span className="text-emerald-400 font-medium">
              {stmResult.written} líneas guardadas en lineas_ucot.
            </span>
            {stmResult.errors.length > 0 && (
              <p className="text-amber-400 mt-1">Errores: {stmResult.errors.join('; ')}</p>
            )}
          </div>
        )}
      </div>

      {successMsg && (
        <div className="bg-emerald-900/50 border border-emerald-500 text-emerald-200 p-6 rounded-2xl flex items-center gap-4 animate-in slide-in-from-top-4">
          <CheckCircle className="w-8 h-8 shrink-0" />
          <span className="text-xl font-bold">{successMsg}</span>
        </div>
      )}

      <div
        {...getRootProps()}
        className={`
                    border-4 border-dashed rounded-3xl p-16 text-center cursor-pointer transition-all duration-300
                    flex flex-col items-center justify-center gap-6 min-h-[300px]
                    ${isDragActive ? 'border-emerald-400 bg-emerald-900/20 scale-105' : 'border-slate-700 hover:border-slate-500 bg-slate-800/50'}
                `}
      >
        <input {...getInputProps()} />

        {uploading ? (
          <div className="flex flex-col items-center gap-4 text-emerald-400">
            <Loader2 className="w-16 h-16 animate-spin" />
            <span className="text-2xl font-bold">Procesando archivo...</span>
          </div>
        ) : analysis ? (
          <div className="space-y-6 w-full">
            <div className="flex flex-col items-center text-emerald-300">
              <FileUp className="w-16 h-16 mb-2" />
              <h3 className="text-2xl font-bold">{analysis.message}</h3>
            </div>

            {/* DIGITAL TWIN EDITOR */}
            {analysis.type === 'JSON_READY' &&
            parsedData?.services.length &&
            parsedData.services.length > 0 &&
            parsedData.type === 'CARTON' ? (
              <div className="bg-slate-900 rounded-xl p-4 border border-slate-700">
                <h4 className="text-sm font-bold text-center text-blue-400 uppercase mb-4 animate-pulse">
                  🛠️ Editor Gemini (Gemelo Digital) - {parsedData.services[0].lineCode}
                </h4>
                <DigitalCartonEditorWrapper
                  serviceData={parsedData.services[0]}
                  onUpdate={(updatedV) => {
                    console.log(updatedV);
                  }}
                />
              </div>
            ) : (
              <div className="w-full overflow-x-auto shadow-sm rounded-lg bg-slate-900 rounded-xl p-4 text-left">
                <h4 className="text-xs font-bold text-slate-500 uppercase mb-2">
                  Vista Previa (mostrando {analysis.preview.length} de {analysis.count} — se
                  ingestarán todos)
                </h4>
                <table className="w-full text-xs text-slate-300 min-w-[400px]">
                  <thead>
                    <tr className="border-b border-slate-700">
                      {analysis.preview[0] &&
                        Object.keys(analysis.preview[0])
                          .slice(0, 8)
                          .map((key) => (
                            <th key={key} className="p-2 text-slate-400">
                              {key}
                            </th>
                          ))}
                    </tr>
                  </thead>
                  <tbody>
                    {analysis.preview.map((row, i) => (
                      <tr key={i} className="border-b border-slate-800 hover:bg-slate-800/50">
                        {Object.entries(row)
                          .slice(0, 8)
                          .map(([key, val], j) => (
                            <td key={j} className="p-2 truncate max-w-[200px]">
                              {String(val)}
                            </td>
                          ))}
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            )}

            <div className="bg-slate-800 p-4 rounded-xl border border-slate-700 space-y-4">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
                <div>
                  <label className="block text-xs uppercase text-slate-500 font-bold mb-1">
                    Import Mode
                  </label>
                  <select
                    className="w-full bg-slate-900 text-white p-2 rounded border border-slate-600 outline-none"
                    value={importMode}
                    onChange={(e) => setImportMode(e.target.value as any)}
                  >
                    <option value="AUTO">Automático</option>
                    <option value="ROTATION">Rotación</option>
                    <option value="CARTON">Cartones</option>
                  </select>
                </div>
                {(importMode === 'ROTATION' || parsedData?.type === 'ROTACION') && (
                  <div>
                    <label className="block text-xs uppercase text-slate-500 font-bold mb-1">
                      Fecha Op.
                    </label>
                    <input
                      type="date"
                      className="w-full bg-slate-900 text-white p-2 rounded border border-slate-600 outline-none"
                      value={selectedDate}
                      onChange={(e) => setSelectedDate(e.target.value)}
                    />
                  </div>
                )}
              </div>

              <div className="pt-4 border-t border-slate-700">
                <div className="flex items-center gap-3 mb-3">
                  <input
                    type="checkbox"
                    id="publishCheck"
                    checked={publishToCloud}
                    onChange={(e) => setPublishToCloud(e.target.checked)}
                    className="w-5 h-5 rounded border-slate-600 text-emerald-500 focus:ring-emerald-500 bg-slate-900"
                  />
                  <label
                    htmlFor="publishCheck"
                    className="flex flex-col cursor-pointer select-none"
                  >
                    <span className="text-white font-bold flex items-center gap-2">
                      <Cloud className="w-4 h-4 text-blue-400" />
                      Publicar Archivo en Matriz de Servicio
                    </span>
                    <span className="text-xs text-slate-400">
                      Hace que este archivo sea visible para todos los usuarios en tiempo real.
                    </span>
                  </label>
                </div>
                {publishToCloud && (
                  <div className="ml-8">
                    <label className="block text-xs uppercase text-slate-500 font-bold mb-1">
                      Área de Publicación
                    </label>
                    <select
                      value={uploadArea}
                      onChange={(e) => setUploadArea(e.target.value as any)}
                      className="w-full bg-slate-900 border border-slate-600 rounded px-3 py-2 text-sm text-white"
                    >
                      <option value="TRAFFIC">Tránsito (Matriz Operativa)</option>
                      <option value="FLEET">Flota (Inventario)</option>
                      <option value="RRHH">RRHH (Planilla)</option>
                    </select>
                  </div>
                )}
              </div>
            </div>

            <div className="flex gap-4 justify-center pt-4">
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setFile(null);
                  setAnalysis(null);
                  setParsedData(null);
                }}
                className="px-6 py-3 rounded-xl bg-slate-700 hover:bg-slate-600 font-bold transition-colors"
              >
                Cancelar
              </button>
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  confirmUpload();
                }}
                className="px-8 py-3 rounded-xl bg-emerald-600 hover:bg-emerald-500 text-white font-bold shadow-lg flex items-center gap-2"
              >
                <Database className="w-5 h-5" />
                {publishToCloud ? 'INGESTAR Y PUBLICAR' : 'SOLO INGESTAR'}
              </button>
            </div>
          </div>
        ) : (
          <>
            <div className="w-24 h-24 bg-slate-700 rounded-full flex items-center justify-center mb-4 shadow-xl">
              <Upload className="w-10 h-10 text-white" />
            </div>
            <div className="space-y-2">
              <p className="text-2xl font-bold text-white">Arrastra tus archivos Excel aquí</p>
              <p className="text-slate-400">Publicar en Matriz o Ingestar Datos</p>
            </div>
          </>
        )}
      </div>

      {/* Keeping Existing Simulation/Reset UI */}
      <div className="bg-slate-900 border border-slate-700 rounded-3xl p-8 space-y-6 opacity-75 hover:opacity-100 transition-opacity">
        <div className="flex items-center gap-4">
          <div className="p-3 bg-purple-500/20 rounded-xl">
            <Play className="w-8 h-8 text-purple-400" />
          </div>
          <div>
            <h2 className="text-2xl font-bold text-white">Simulación Operativa</h2>
            <p className="text-slate-400">Control de escenario de tráfico sintético.</p>
          </div>
        </div>
        <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
          <button
            onClick={downloadReport}
            className="flex items-center justify-center gap-3 p-4 bg-slate-800 rounded-xl"
          >
            <Download className="w-6 h-6 text-blue-400" />{' '}
            <span className="font-bold text-slate-200">Reporte PDF</span>
          </button>
          <button
            onClick={resetSimulation}
            className="flex items-center justify-center gap-3 p-4 bg-slate-800 rounded-xl"
          >
            <Trash2 className="w-6 h-6 text-red-400" />{' '}
            <span className="font-bold text-slate-200">Limpiar Simulación</span>
          </button>
        </div>
      </div>
    </div>
  );
};
export default DataIngestion;

import { useState, useEffect } from 'react';
import { API_URL } from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import { UserPlus, Users, Search, Save, X, FileUp, FileDown, Download } from 'lucide-react';
import { DataImportService } from '../../services/api';

const Employees = () => {
  const { token } = useAuth();
  const [employees, setEmployees] = useState<any[]>([]);
  const [showModal, setShowModal] = useState(false);
  const [showImportModal, setShowImportModal] = useState(false);
  const [loading, setLoading] = useState(false);
  const [importing, setImporting] = useState(false);
  const [file, setFile] = useState<File | null>(null);

  // Form State
  const [form, setForm] = useState({
    firstName: '',
    lastName: '',
    ci: '',
    internalNumber: '',
    position: 'Chofer',
    role: 'User',
  });

  useEffect(() => {
    loadEmployees();
  }, []);

  const loadEmployees = async () => {
    // Fetch users for now as they contain employee info
    // Ideal: fetch /api/employees endpoint if exists, otherwise /api/users
    try {
      const res = await fetch(`${API_URL}/users`, {
        headers: { Authorization: `Bearer ${token}` },
      });
      if (res.ok) setEmployees(await res.json());
    } catch (e) {
      console.error(e);
    }
  };

  const handleSave = async (e: React.FormEvent) => {
    e.preventDefault();
    setLoading(true);
    try {
      // Auto-generate password = CI
      const payload = {
        ...form,
        password: form.ci,
      };

      const res = await fetch(`${API_URL}/auth/register`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${token}`,
        },
        body: JSON.stringify(payload),
      });

      if (res.ok) {
        alert('Empleado creado correctamente');
        setShowModal(false);
        setForm({
          firstName: '',
          lastName: '',
          ci: '',
          internalNumber: '',
          position: 'Chofer',
          role: 'User',
        });
        loadEmployees();
      } else {
        const err = await res.json();
        alert('Error: ' + err.message);
      }
    } catch (e) {
      alert('Error de conexión');
    } finally {
      setLoading(false);
    }
  };

  const handleExport = async () => {
    try {
      const blob = await DataImportService.exportEmployees();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `empleados_ucot_${new Date().toISOString().split('T')[0]}.xlsx`;
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
    } catch (e) {
      alert('Error al exportar');
    }
  };

  const handleImport = async () => {
    if (!file) return;
    setImporting(true);
    try {
      const formData = new FormData();
      formData.append('file', file);
      const res = await DataImportService.uploadEmployees(formData);
      alert(
        `Éxito: ${(res as { success?: boolean; count?: number; errors?: unknown[] }).success ?? res.count} procesados. Errores: ${(res as { errors?: unknown[] }).errors?.length ?? 0}`,
      );
      setShowImportModal(false);
      setFile(null);
      loadEmployees();
    } catch (e: any) {
      alert('Error en importación: ' + e.message);
    } finally {
      setImporting(false);
    }
  };

  const handleDownloadTemplate = async () => {
    try {
      const blob = await DataImportService.downloadEmployeeTemplate();
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = 'plantilla_empleados_ucot.xlsx';
      document.body.appendChild(a);
      a.click();
      document.body.removeChild(a);
    } catch (e) {
      alert('Error al descargar plantilla');
    }
  };

  return (
    <div className="p-6 max-w-7xl mx-auto animate-fade-in-up">
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-white flex items-center gap-3">
            <Users className="w-8 h-8 text-primary-500" />
            Gestión de Empleados
          </h1>
          <p className="text-slate-400">Administración de RRHH y Usuarios del Sistema</p>
        </div>
        <div className="flex gap-3">
          <button
            onClick={handleExport}
            className="bg-slate-800 hover:bg-slate-700 text-slate-300 px-4 py-2 rounded-xl border border-slate-700 flex items-center gap-2 transition-all"
          >
            <FileDown className="w-5 h-5" />
            Exportar
          </button>
          <button
            onClick={() => setShowImportModal(true)}
            className="bg-slate-800 hover:bg-slate-700 text-slate-300 px-4 py-2 rounded-xl border border-slate-700 flex items-center gap-2 transition-all"
          >
            <FileUp className="w-5 h-5" />
            Importar (XLSX)
          </button>
          <button
            onClick={() => setShowModal(true)}
            className="btn btn-primary flex items-center gap-2 shadow-lg shadow-primary-900/20"
          >
            <UserPlus className="w-5 h-5" />
            Nuevo Empleado
          </button>
        </div>
      </div>

      {/* Employee List */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl overflow-hidden shadow-xl">
        <table className="w-full">
          <thead className="bg-slate-950 text-slate-400 uppercase text-xs font-bold">
            <tr>
              <th className="p-4 text-left">Empleado</th>
              <th className="p-4 text-left">Cédula / Legajo</th>
              <th className="p-4 text-left">Cargo</th>
              <th className="p-4 text-left">Rol Sistema</th>
              <th className="p-4 text-center">Estado</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-800">
            {employees.map((emp) => (
              <tr key={emp.id} className="hover:bg-slate-800/50 transition-colors">
                <td className="p-4">
                  <div className="flex items-center gap-3">
                    <div className="w-10 h-10 rounded-full bg-slate-700 flex items-center justify-center text-white font-bold">
                      {emp.firstName?.[0]}
                    </div>
                    <div>
                      <div className="font-bold text-white">{emp.fullName}</div>
                      <div className="text-xs text-slate-500">{emp.email || 'Sin email'}</div>
                    </div>
                  </div>
                </td>
                <td className="p-4">
                  <div className="text-white font-mono">{emp.ci}</div>
                  <div className="text-xs text-slate-500">Int: {emp.internalNumber}</div>
                </td>
                <td className="p-4 text-slate-300">{emp.jobRole?.name || emp.position || '—'}</td>
                <td className="p-4">
                  <span
                    className={`px-2 py-1 rounded text-xs font-bold ${emp.role === 'Admin' || emp.role === 'SuperAdmin' ? 'bg-purple-500/20 text-purple-400' : 'bg-slate-700 text-slate-300'}`}
                  >
                    {emp.role}
                  </span>
                </td>
                <td className="p-4 text-center">
                  <span className="w-3 h-3 rounded-full bg-emerald-500 inline-block"></span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-lg shadow-2xl p-6 animate-fade-in-up">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white">Nuevo Empleado</h2>
              <button
                onClick={() => setShowModal(false)}
                className="text-slate-400 hover:text-white"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleSave} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="label">Nombre</label>
                  <input
                    className="input-field"
                    required
                    value={form.firstName}
                    onChange={(e) => setForm({ ...form, firstName: e.target.value })}
                  />
                </div>
                <div>
                  <label className="label">Apellido</label>
                  <input
                    className="input-field"
                    required
                    value={form.lastName}
                    onChange={(e) => setForm({ ...form, lastName: e.target.value })}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="label">Cédula (Usuario)</label>
                  <input
                    className="input-field"
                    required
                    placeholder="1.234.567-8"
                    value={form.ci}
                    onChange={(e) => setForm({ ...form, ci: e.target.value })}
                  />
                </div>
                <div>
                  <label className="label">Nro. Legajo</label>
                  <input
                    className="input-field"
                    placeholder="Opcional"
                    value={form.internalNumber}
                    onChange={(e) => setForm({ ...form, internalNumber: e.target.value })}
                  />
                </div>
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="label">Cargo (RRHH)</label>
                  <select
                    className="input-field"
                    value={form.position}
                    onChange={(e) => setForm({ ...form, position: e.target.value })}
                  >
                    <option value="Chofer">Chofer</option>
                    <option value="Inspector">Inspector</option>
                    <option value="Mecánico">Mecánico</option>
                    <option value="Administrativo">Administrativo</option>
                  </select>
                </div>
                <div>
                  <label className="label">Rol Sistema</label>
                  <select
                    className="input-field"
                    value={form.role}
                    onChange={(e) => setForm({ ...form, role: e.target.value })}
                  >
                    <option value="User">Usuario Básico</option>
                    <option value="Inspector">Inspector</option>
                    <option value="Admin">Administrador</option>
                  </select>
                </div>
              </div>

              <div className="bg-blue-900/20 p-3 rounded-lg border border-blue-500/20 text-xs text-blue-300 mt-4">
                <p>ℹ️ La contraseña inicial será el número de Cédula.</p>
              </div>

              <button
                disabled={loading}
                className="btn btn-primary w-full mt-4 flex justify-center items-center gap-2"
              >
                {loading ? (
                  <span className="animate-spin rounded-full h-4 w-4 border-2 border-white/20 border-t-white"></span>
                ) : (
                  <Save className="w-5 h-5" />
                )}
                Crear Empleado
              </button>
            </form>
          </div>
        </div>
      )}

      {/* Import Modal */}
      {showImportModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-700 rounded-2xl w-full max-w-md shadow-2xl p-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white">Importación Masiva</h2>
              <button
                onClick={() => setShowImportModal(false)}
                className="text-slate-400 hover:text-white"
              >
                <X className="w-6 h-6" />
              </button>
            </div>

            <div className="space-y-6">
              <div className="text-center p-6 border-2 border-dashed border-slate-700 rounded-xl hover:border-primary-500 transition-colors cursor-pointer group">
                <input
                  type="file"
                  accept=".xlsx"
                  className="hidden"
                  id="employee-file"
                  onChange={(e) => setFile(e.target.files?.[0] || null)}
                />
                <label htmlFor="employee-file" className="cursor-pointer">
                  <FileUp className="w-12 h-12 text-slate-500 mx-auto mb-2 group-hover:text-primary-400" />
                  <p className="text-sm text-slate-300">
                    {file ? file.name : 'Seleccionar archivo Excel (.xlsx)'}
                  </p>
                  <p className="text-[10px] text-slate-500 mt-1">Soporta más de 1000 registros</p>
                </label>
              </div>

              <button
                onClick={handleDownloadTemplate}
                className="w-full flex items-center justify-center gap-2 text-xs text-primary-400 hover:text-primary-300"
              >
                <Download className="w-4 h-4" /> Bajar Plantilla RRHH
              </button>

              <div className="pt-4 flex gap-3 border-t border-slate-800">
                <button
                  disabled={importing}
                  onClick={() => setShowImportModal(false)}
                  className="flex-1 py-2 text-slate-400 hover:text-white"
                >
                  Cancelar
                </button>
                <button
                  disabled={importing || !file}
                  onClick={handleImport}
                  className="flex-1 btn btn-primary py-2 flex justify-center items-center gap-2"
                >
                  {importing && (
                    <span className="animate-spin rounded-full h-4 w-4 border-2 border-white/20 border-t-white"></span>
                  )}
                  Iniciar Carga
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Employees;

import React, { useEffect, useState } from 'react';
import {
  AlertTriangle,
  CheckCircle,
  Clock,
  Plus,
  Search,
  Settings,
  Briefcase,
  Trash2,
  Camera,
} from 'lucide-react';
import {
  MaintenanceService,
  FleetService,
  DepartmentService,
  UniversalService,
} from '../../services/api';
import { useAuth } from '../../context/AuthContext';
import clsx from 'clsx';

const STATUS_CONFIG: any = {
  ENVIADO: { label: 'Enviado', color: 'bg-yellow-500/20 text-yellow-400', icon: Clock },
  RECIBIDO: { label: 'Recibido', color: 'bg-blue-500/20 text-blue-400', icon: CheckCircle },
  EN_PROCESO: { label: 'En Proceso', color: 'bg-indigo-500/20 text-indigo-400', icon: Settings },
  PROGRAMADO: { label: 'Programado', color: 'bg-purple-500/20 text-purple-400', icon: Clock },
  DESCARTADO: { label: 'Descartado', color: 'bg-slate-500/20 text-slate-400', icon: AlertTriangle },
  FINALIZADO: { label: 'Finalizado', color: 'bg-green-500/20 text-green-400', icon: CheckCircle },
};

const MaintenanceDashboard = () => {
  const [reports, setReports] = useState<any[]>([]);
  const [vehicles, setVehicles] = useState<any[]>([]);
  const [departments, setDepartments] = useState<any[]>([]);
  const [loading, setLoading] = useState(true);
  const [filterCheck, setFilterCheck] = useState('all'); // all, pending, process

  // Create Report Modal State
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [newReport, setNewReport] = useState({
    vehicleId: '',
    departmentId: '',
    title: '',
    description: '',
    priority: 'NORMAL',
    photoUrl: '', // Will keep compatibility
    evidencePhotos: '', // Base64
  });

  // Solve/Close Ticket Modal State
  const [processModalOpen, setProcessModalOpen] = useState(false);
  const [auditReport, setAuditReport] = useState<any>(null);
  const [solution, setSolution] = useState('');
  const [availableParts, setAvailableParts] = useState<any[]>([]);
  const [selectedPartId, setSelectedPartId] = useState('');
  const [selectedQty, setSelectedQty] = useState(1);
  const [usedParts, setUsedParts] = useState<any[]>([]); // { partId, sku, description, quantity }

  useEffect(() => {
    const init = async () => {
      setLoading(true);
      try {
        const [vData, dData] = await Promise.all([
          FleetService.getVehicles(),
          DepartmentService.getAll(),
        ]);
        setVehicles(vData);
        setDepartments(dData);
        fetchReports();

        // Fetch Parts for autocomplete
        UniversalService.list('parts', 1, 1000)
          .then((res: any) => {
            setAvailableParts(res.data || []);
          })
          .catch(() => console.error('Error loading parts'));
      } catch (error) {
        console.error(error);
      } finally {
        setLoading(false);
      }
    };
    init();
  }, []);

  const fetchReports = async () => {
    try {
      const data = await MaintenanceService.getAll(
        (filterCheck !== 'all' ? { status: filterCheck } : {}) as { vehicleId?: string },
      );
      setReports(data);
    } catch (e) {
      console.error(e);
    }
  };

  const handleImageUpload = async (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      // Optimistic Loading State or dedicated upload state could be used
      // but we reuse the main form since it blocks submit usually
      // Here we just fire and forget, blocking via async if we wanted.

      try {
        const res = await MaintenanceService.uploadFile(file);
        if (res.url) {
          setNewReport({ ...newReport, evidencePhotos: res.url });
          // Optional: Toast success
        }
      } catch (error) {
        console.error('Upload failed', error);
        alert('Error al subir imagen');
      }
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      await MaintenanceService.create(newReport);
      setIsModalOpen(false);
      fetchReports();
      setNewReport({
        vehicleId: '',
        departmentId: '',
        title: '',
        description: '',
        priority: 'NORMAL',
        photoUrl: '',
        evidencePhotos: '',
      });
    } catch (error) {
      alert('Error al crear reporte');
    }
  };

  const handleOpenProcess = (report: any) => {
    setAuditReport(report);
    setSolution('');
    setUsedParts([]);
    setProcessModalOpen(true);
  };

  const handleAddPart = () => {
    if (!selectedPartId) return;
    const part = availableParts.find((p) => String(p.id) === selectedPartId);
    if (!part) return;

    setUsedParts((prev) => [
      ...prev,
      {
        partId: part.id,
        sku: part.sku,
        description: part.description,
        quantity: selectedQty,
      },
    ]);

    setSelectedPartId('');
    setSelectedQty(1);
  };

  const handleRemovePart = (index: number) => {
    setUsedParts((prev) => prev.filter((_, i) => i !== index));
  };

  // --- RBAC CHECK ---
  const { user } = useAuth(); // Import useAuth hook at top level first! This snippet assumes useAuth is imported.
  // However, I need to add useAuth import at top of file first.

  const handleCloseTicket = async () => {
    if (!auditReport) return;

    // RBAC: Only Admin/SuperAdmin/Encargado
    // Assuming 'Encargado' role exists or is mapped to Admin/SuperAdmin permissions for this module.
    // If strictly 'Encargado' is a role string:
    const authorizedRoles = ['Admin', 'SuperAdmin', 'Encargado'];
    if (!user || !authorizedRoles.includes(user.role)) {
      alert('Acceso Denegado: Solo el Encargado de Taller o Admin puede cerrar tickets.');
      return;
    }

    // VALIDATION: Mandatory Description
    if (!solution || solution.trim().length < 5) {
      alert(
        'REQUISITO: Debe detallar la solución técnica aplicada par poder cerrar la incidencia.',
      );
      return;
    }

    // Confirmation (Implicit in "Confirmar y Cerrar" button, but let's be double sure if critical)
    if (!confirm('¿Confirma que el vehículo está reparado y listo para operar?')) return;

    try {
      await MaintenanceService.closeTicket(auditReport.id, {
        solution,
        partsUsed: usedParts,
      });
      setProcessModalOpen(false);
      fetchReports();
      alert('Ticket cerrado correctamente. Stock actualizado.');
    } catch (error) {
      console.error(error);
      alert('Error al cerrar ticket');
    }
  };

  return (
    <div className="space-y-6 animate-fade-in-up">
      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center gap-4">
        <div>
          <h1 className="text-2xl font-bold text-white flex items-center gap-2">
            <Settings className="w-8 h-8 text-primary-500" />
            Mantenimiento y Denuncias
          </h1>
          <p className="text-slate-400">Gestión de novedades, roturas y mantenimientos de flota.</p>
        </div>
        <button
          onClick={() => setIsModalOpen(true)}
          className="btn btn-primary flex items-center gap-2"
        >
          <Plus className="w-5 h-5" /> Nueva Denuncia
        </button>
      </div>

      {/* Filters */}
      <div className="flex gap-2 overflow-x-auto pb-2">
        {['all', 'ENVIADO', 'EN_PROCESO', 'FINALIZADO'].map((status) => (
          <button
            key={status}
            onClick={() => setFilterCheck(status)}
            className={clsx(
              'px-4 py-2 rounded-full text-sm font-medium transition-colors whitespace-nowrap',
              filterCheck === status
                ? 'bg-primary-600 text-white'
                : 'bg-slate-800 text-slate-400 hover:text-white',
            )}
          >
            {status === 'all' ? 'Todos' : STATUS_CONFIG[status]?.label || status}
          </button>
        ))}
      </div>

      {/* Reports Grid */}
      {loading ? (
        <div className="text-center py-12 text-slate-400">Cargando reportes...</div>
      ) : reports.length === 0 ? (
        <div className="text-center py-12 bg-slate-900 rounded-xl border border-slate-800">
          <Search className="w-12 h-12 text-slate-600 mx-auto mb-4" />
          <h3 className="text-lg font-bold text-white">Sin Novedades</h3>
          <p className="text-slate-400">No hay reportes que coincidan con los filtros.</p>
        </div>
      ) : (
        <div className="grid gap-4 md:grid-cols-2 xl:grid-cols-3">
          {reports.map((report) => (
            <div
              key={report.id}
              className="bg-slate-900 border border-slate-800 rounded-xl p-5 hover:border-slate-700 transition-colors flex flex-col relative group"
            >
              <div className="flex justify-between items-start mb-3">
                <div className="flex items-center gap-2">
                  <div className="font-bold text-xl text-white">
                    Unit {report.vehicle?.internalNumber}
                  </div>
                  {report.vehicle?.plate && (
                    <div className="text-xs text-slate-500 bg-slate-800 px-2 py-0.5 rounded">
                      {report.vehicle.plate}
                    </div>
                  )}
                </div>
                <div
                  className={clsx(
                    'px-2 py-1 rounded text-xs font-bold flex items-center gap-1',
                    STATUS_CONFIG[report.status]?.color,
                  )}
                >
                  {STATUS_CONFIG[report.status]?.label || report.status}
                </div>
              </div>

              <h3 className="font-medium text-white mb-1 truncate">{report.title}</h3>
              <p className="text-sm text-slate-400 line-clamp-2 mb-4 flex-1">
                {report.description}
              </p>

              {/* Process Button Overlay */}
              {report.status !== 'FINALIZADO' && (
                <div className="absolute top-4 right-4">
                  <button
                    onClick={() => handleOpenProcess(report)}
                    className="bg-emerald-600 hover:bg-emerald-500 text-white p-2 rounded-full shadow-lg opacity-0 group-hover:opacity-100 transition-opacity"
                    title="Resolver / Cerrar Ticket"
                  >
                    <CheckCircle className="w-5 h-5" />
                  </button>
                </div>
              )}

              <div className="flex items-center justify-between mt-auto pt-4 border-t border-slate-800 text-xs text-slate-500">
                <div className="flex items-center gap-1">
                  <Briefcase className="w-3 h-3" />
                  {report.department?.name || 'General'}
                </div>
                <div>{new Date(report.createdAt).toLocaleDateString()}</div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* New Report Modal */}
      {isModalOpen && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 w-full max-w-lg rounded-2xl border border-slate-800 shadow-xl p-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white">Nueva Denuncia / Reporte</h2>
              <button
                onClick={() => setIsModalOpen(false)}
                className="text-slate-400 hover:text-white"
              >
                <XIcon className="w-6 h-6" />
              </button>
            </div>

            <form onSubmit={handleSubmit} className="space-y-4">
              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm text-slate-400 mb-1">Vehículo / Coche</label>
                  <select
                    className="input-field w-full"
                    value={newReport.vehicleId}
                    onChange={(e) => setNewReport({ ...newReport, vehicleId: e.target.value })}
                    required
                  >
                    <option value="">Seleccionar...</option>
                    {vehicles.map((v) => (
                      <option key={v.id} value={v.id}>
                        {v.internalNumber} - {v.plate}
                      </option>
                    ))}
                  </select>
                </div>
                <div>
                  <label className="block text-sm text-slate-400 mb-1">Área Destino</label>
                  <select
                    className="input-field w-full"
                    value={newReport.departmentId}
                    onChange={(e) => setNewReport({ ...newReport, departmentId: e.target.value })}
                  >
                    <option value="">General / Sin Asignar</option>
                    {departments.map((d) => (
                      <option key={d.id} value={d.id}>
                        {d.name}
                      </option>
                    ))}
                  </select>
                </div>
              </div>

              <div>
                <label className="block text-sm text-slate-400 mb-1">Título Breve</label>
                <input
                  type="text"
                  className="input-field w-full"
                  placeholder="Ej. Luz trasera quemada, Aire no enfría"
                  value={newReport.title}
                  onChange={(e) => setNewReport({ ...newReport, title: e.target.value })}
                  required
                />
              </div>

              {/* Evidence Photo Upload */}
              <div>
                <label className="block text-sm text-slate-400 mb-1 cursor-pointer flex items-center gap-2">
                  <Camera className="w-4 h-4" />
                  Foto de Evidencia
                </label>
                <input
                  type="file"
                  accept="image/*"
                  onChange={handleImageUpload}
                  className="block w-full text-sm text-slate-400
                                        file:mr-4 file:py-2 file:px-4
                                        file:rounded-full file:border-0
                                        file:text-sm file:font-semibold
                                        file:bg-primary-600 file:text-white
                                        hover:file:bg-primary-500
                                    "
                />
                {newReport.evidencePhotos && (
                  <div className="mt-2">
                    <img
                      src={newReport.evidencePhotos}
                      alt="Preview"
                      className="h-20 w-auto rounded border border-slate-700 object-cover"
                    />
                  </div>
                )}
              </div>

              <div>
                <label className="block text-sm text-slate-400 mb-1">Descripción Detallada</label>
                <textarea
                  className="input-field w-full"
                  rows={3}
                  placeholder="Describa el problema..."
                  value={newReport.description}
                  onChange={(e) => setNewReport({ ...newReport, description: e.target.value })}
                  required
                />
              </div>

              <div>
                <label className="block text-sm text-slate-400 mb-1">Prioridad</label>
                <div className="flex gap-4">
                  {['LOW', 'NORMAL', 'HIGH', 'CRITICAL'].map((p) => (
                    <label key={p} className="flex items-center gap-2 cursor-pointer">
                      <input
                        type="radio"
                        name="priority"
                        value={p}
                        checked={newReport.priority === p}
                        onChange={(e) => setNewReport({ ...newReport, priority: e.target.value })}
                        className="accent-primary-500"
                      />
                      <span className="text-sm text-slate-300 capitalize">{p.toLowerCase()}</span>
                    </label>
                  ))}
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button
                  type="button"
                  onClick={() => setIsModalOpen(false)}
                  className="flex-1 py-2 text-slate-400 hover:text-white"
                >
                  Cancelar
                </button>
                <button type="submit" className="flex-1 btn btn-primary py-2">
                  Crear Reporte
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Process/Close Ticket Modal */}
      {processModalOpen && auditReport && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-black/80 backdrop-blur-sm">
          <div className="bg-slate-900 w-full max-w-lg rounded-2xl border border-slate-800 shadow-xl p-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-xl font-bold text-white">Cerrar Reparación</h2>
              <button
                onClick={() => setProcessModalOpen(false)}
                className="text-slate-400 hover:text-white"
              >
                <XIcon className="w-6 h-6" />
              </button>
            </div>

            <div className="space-y-4">
              <div className="bg-slate-800/50 p-3 rounded-lg border border-slate-700">
                <div className="text-sm font-bold text-white">
                  Unit {auditReport.vehicle?.internalNumber} - {auditReport.title}
                </div>
                <div className="text-xs text-slate-400">{auditReport.description}</div>
              </div>

              <div>
                <label className="block text-sm text-slate-400 mb-1">Solución Aplicada</label>
                <textarea
                  className="input-field w-full"
                  rows={3}
                  placeholder="Detalla qué trabajo se realizó..."
                  value={solution}
                  onChange={(e) => setSolution(e.target.value)}
                />
              </div>

              <div className="p-3 border border-slate-700 rounded-lg">
                <label className="block text-sm font-bold text-slate-300 mb-2">
                  Repuestos Utilizados
                </label>

                <div className="flex gap-2 mb-3">
                  <select
                    className="input-field flex-1 text-xs"
                    value={selectedPartId}
                    onChange={(e) => setSelectedPartId(e.target.value)}
                  >
                    <option value="">Buscar repuesto...</option>
                    {availableParts.map((p) => (
                      <option key={p.id} value={p.id}>
                        {p.sku} - {p.description} (Stock: {p.currentStock})
                      </option>
                    ))}
                  </select>
                  <input
                    type="number"
                    min="1"
                    className="input-field w-16 text-center"
                    value={selectedQty}
                    onChange={(e) => setSelectedQty(Math.max(1, Number(e.target.value)))}
                  />
                  <button
                    onClick={handleAddPart}
                    disabled={!selectedPartId}
                    className="bg-primary-600 px-3 rounded-lg text-white hover:bg-primary-500 disabled:opacity-50"
                  >
                    <Plus className="w-4 h-4" />
                  </button>
                </div>

                {/* Parts List */}
                <div className="space-y-2">
                  {usedParts.map((part, idx) => (
                    <div
                      key={idx}
                      className="flex justify-between items-center bg-slate-800 p-2 rounded text-sm"
                    >
                      <div>
                        <div className="text-white font-medium">
                          {part.quantity}x {part.sku}
                        </div>
                        <div className="text-xs text-slate-400">{part.description}</div>
                      </div>
                      <button
                        onClick={() => handleRemovePart(idx)}
                        className="text-red-400 hover:text-red-300"
                      >
                        <Trash2 className="w-4 h-4" />
                      </button>
                    </div>
                  ))}
                  {usedParts.length === 0 && (
                    <div className="text-xs text-slate-500 text-center py-2">
                      No se usaron repuestos
                    </div>
                  )}
                </div>
              </div>

              <div className="pt-4 flex gap-3">
                <button
                  onClick={() => setProcessModalOpen(false)}
                  className="flex-1 py-2 text-slate-400 hover:text-white"
                >
                  Cancelar
                </button>
                <button
                  onClick={handleCloseTicket}
                  className="flex-1 btn bg-emerald-600 hover:bg-emerald-500 text-white py-2 rounded-xl font-bold shadow-lg"
                >
                  Confirmar y Cerrar
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

// Helper Icon for Modal Close
const XIcon = ({ className }: { className?: string }) => (
  <svg
    xmlns="http://www.w3.org/2000/svg"
    width="24"
    height="24"
    viewBox="0 0 24 24"
    fill="none"
    stroke="currentColor"
    strokeWidth="2"
    strokeLinecap="round"
    strokeLinejoin="round"
    className={className}
  >
    <line x1="18" y1="6" x2="6" y2="18"></line>
    <line x1="6" y1="6" x2="18" y2="18"></line>
  </svg>
);

export default MaintenanceDashboard;

/**
 * Parámetros del Sistema: tolerancia de desvío (min) y otros. Persistido en Firestore system_config.
 */
import { useState, useEffect } from 'react';
import { Settings, Save, Loader2 } from 'lucide-react';
import { SystemConfigService } from '../../services/firestore/systemConfig';

export default function SystemParamsPage() {
  const [toleranciaMinutos, setToleranciaMinutos] = useState(10);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState(false);
  const [message, setMessage] = useState<string | null>(null);

  useEffect(() => {
    SystemConfigService.get()
      .then((c) => {
        setToleranciaMinutos(c.toleranciaMinutos);
      })
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const handleSave = async () => {
    setSaving(true);
    setMessage(null);
    try {
      await SystemConfigService.setToleranciaMinutos(toleranciaMinutos);
      setMessage('Guardado. El motor de desvíos usará ±' + toleranciaMinutos + ' min.');
    } catch (e) {
      setMessage('Error al guardar.');
    } finally {
      setSaving(false);
    }
  };

  if (loading) {
    return (
      <div className="flex items-center justify-center p-12">
        <Loader2 className="w-8 h-8 animate-spin text-primary-400" />
      </div>
    );
  }

  return (
    <div className="animate-fade-in space-y-6 max-w-2xl">
      <h1 className="text-2xl font-bold text-white flex items-center gap-2">
        <Settings className="w-8 h-8 text-primary-400" />
        Parámetros del Sistema
      </h1>
      <p className="text-slate-400 text-sm">
        Valores leídos globalmente por el motor de desvíos (puntualidad, semáforo Listero).
      </p>
      <div className="glass-panel p-6 rounded-2xl border border-slate-700">
        <label className="block text-slate-300 font-medium mb-2">
          Margen de tolerancia (minutos)
        </label>
        <p className="text-xs text-slate-500 mb-2">
          Desvío dentro de ± este valor se considera puntual (ej. ±10 min).
        </p>
        <div className="flex flex-wrap items-center gap-3">
          <input
            type="number"
            min={0}
            max={60}
            value={toleranciaMinutos}
            onChange={(e) => setToleranciaMinutos(Number(e.target.value) || 0)}
            className="bg-slate-800 border border-slate-600 rounded-lg px-4 py-2 text-white w-24"
          />
          <span className="text-slate-400 text-sm">minutos</span>
          <button
            type="button"
            onClick={handleSave}
            disabled={saving}
            className="inline-flex items-center gap-2 px-4 py-2 bg-primary-600 hover:bg-primary-500 text-white font-bold rounded-xl disabled:opacity-50"
          >
            {saving ? <Loader2 className="w-4 h-4 animate-spin" /> : <Save className="w-4 h-4" />}
            Guardar
          </button>
        </div>
        {message && (
          <p
            className={
              message.startsWith('Error')
                ? 'text-red-400 mt-2 text-sm'
                : 'text-emerald-400 mt-2 text-sm'
            }
          >
            {message}
          </p>
        )}
      </div>
    </div>
  );
}

