import React, { useState, useEffect } from 'react';
import { Plus, Building2, Copy } from 'lucide-react';
import api from '../../services/api';

const TenantsManager = () => {
  const [tenants, setTenants] = useState<any[]>([]);
  const [showModal, setShowModal] = useState(false);

  // Form
  const [formData, setFormData] = useState({
    name: '',
    slug: '',
    adminInternalNumber: '',
    adminFirstName: '',
    adminLastName: '',
    adminPassword: '',
  });

  const [createdInfo, setCreatedInfo] = useState<any>(null);

  useEffect(() => {
    fetchTenants();
  }, []);

  const fetchTenants = async () => {
    try {
      const res = await api.get('/tenants');
      setTenants((res.data || []) as any[]);
    } catch (error) {
      console.error(error);
    }
  };

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    try {
      const res = await api.post('/tenants', formData);
      setCreatedInfo(res.data);
      setShowModal(false);
      fetchTenants();
      alert('Empresa creada exitosamente');
    } catch (error: any) {
      alert(error.response?.data?.message || 'Error al crear empresa');
    }
  };

  return (
    <div className="space-y-6">
      <div className="flex justify-between items-center">
        <h1 className="text-2xl font-bold text-white flex items-center gap-2">
          <Building2 className="text-pink-500" />
          Gestión de Empresas (Tenants)
        </h1>
        <button
          onClick={() => setShowModal(true)}
          className="bg-pink-600 hover:bg-pink-700 text-white px-4 py-2 rounded-lg flex items-center gap-2"
        >
          <Plus size={20} />
          Nueva Empresa
        </button>
      </div>

      {/* List */}
      <div className="bg-slate-800 rounded-xl overflow-hidden border border-slate-700 overflow-x-auto touch-pan-x">
        <table className="w-full text-left min-w-[700px]">
          <thead className="bg-slate-900/50 text-slate-400 text-sm uppercase">
            <tr>
              <th className="p-4">ID</th>
              <th className="p-4">Nombre</th>
              <th className="p-4">Slug / Código</th>
              <th className="p-4">Usuarios</th>
              <th className="p-4">Estado</th>
            </tr>
          </thead>
          <tbody className="divide-y divide-slate-700">
            {tenants.map((t) => (
              <tr key={t.id} className="hover:bg-slate-700/30">
                <td className="p-4 text-slate-500">#{t.id}</td>
                <td className="p-4 font-medium text-white">{t.name}</td>
                <td className="p-4 font-mono text-xs bg-slate-900/50 px-2 py-1 rounded w-fit">
                  {t.slug}
                </td>
                <td className="p-4 text-slate-400">{t._count?.users || 0}</td>
                <td className="p-4">
                  <span
                    className={`px-2 py-1 rounded text-xs ${t.isActive ? 'bg-green-500/20 text-green-400' : 'bg-red-500/20 text-red-400'}`}
                  >
                    {t.isActive ? 'Activo' : 'Inactivo'}
                  </span>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* Created Success Info */}
      {createdInfo && (
        <div className="bg-green-500/10 border border-green-500/50 p-6 rounded-xl mt-4">
          <h3 className="text-xl font-bold text-green-400 mb-2">¡Empresa Creada!</h3>
          <p className="mb-4">
            Comparte este enlace para que los usuarios se registren directamente:
          </p>

          <div className="flex items-center gap-2 bg-slate-900 p-3 rounded border border-slate-700">
            <code className="flex-1 text-green-300 font-mono text-sm break-all">
              {createdInfo.inviteLink}
            </code>
            <button
              onClick={() => navigator.clipboard.writeText(createdInfo.inviteLink)}
              className="text-slate-400 hover:text-white"
            >
              <Copy size={18} />
            </button>
          </div>

          <div className="mt-4 text-sm text-slate-400">
            <p>
              Admin Inicial:{' '}
              <span className="text-white font-mono">{createdInfo.admin.internalNumber}</span>
            </p>
          </div>
        </div>
      )}

      {/* Modal */}
      {showModal && (
        <div className="fixed inset-0 bg-black/80 flex items-center justify-center z-50 p-4">
          <div className="bg-slate-800 p-6 rounded-xl w-full max-w-lg border border-slate-700">
            <h2 className="text-xl font-bold text-white mb-4">Nueva Empresa</h2>
            <form onSubmit={handleSubmit} className="space-y-4">
              <div>
                <label className="block text-sm text-slate-400 mb-1">Nombre Empresa</label>
                <input
                  required
                  type="text"
                  className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-white"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  placeholder="Ej. Transportes S.A."
                />
              </div>
              <div>
                <label className="block text-sm text-slate-400 mb-1">Slug / Código (Único)</label>
                <input
                  required
                  type="text"
                  className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-white"
                  value={formData.slug}
                  onChange={(e) => setFormData({ ...formData, slug: e.target.value })}
                  placeholder="Ej. transportes-sa"
                />
              </div>

              <div className="border-t border-slate-700 my-4 pt-4">
                <h3 className="text-sm font-semibold text-pink-400 mb-2">
                  Crear Primer Administrador
                </h3>
                <div className="grid grid-cols-2 gap-2 mb-2">
                  <input
                    required
                    type="text"
                    className="bg-slate-900 border border-slate-700 rounded p-2 text-white"
                    value={formData.adminFirstName}
                    onChange={(e) => setFormData({ ...formData, adminFirstName: e.target.value })}
                    placeholder="Nombre"
                  />
                  <input
                    required
                    type="text"
                    className="bg-slate-900 border border-slate-700 rounded p-2 text-white"
                    value={formData.adminLastName}
                    onChange={(e) => setFormData({ ...formData, adminLastName: e.target.value })}
                    placeholder="Apellido"
                  />
                </div>
                <div className="mb-2">
                  <input
                    required
                    type="text"
                    className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-white"
                    value={formData.adminInternalNumber}
                    onChange={(e) =>
                      setFormData({ ...formData, adminInternalNumber: e.target.value })
                    }
                    placeholder="Número Interno Admin (Ej. 9999)"
                  />
                </div>
                <div>
                  <input
                    required
                    type="password"
                    className="w-full bg-slate-900 border border-slate-700 rounded p-2 text-white"
                    value={formData.adminPassword}
                    onChange={(e) => setFormData({ ...formData, adminPassword: e.target.value })}
                    placeholder="Contraseña Admin"
                  />
                </div>
              </div>

              <div className="flex justify-end gap-2 mt-6">
                <button
                  type="button"
                  onClick={() => setShowModal(false)}
                  className="px-4 py-2 text-slate-400 hover:text-white"
                >
                  Cancelar
                </button>
                <button
                  type="submit"
                  className="bg-pink-600 hover:bg-pink-700 px-4 py-2 rounded text-white font-medium"
                >
                  Crear Empresa
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default TenantsManager;

import { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { API_URL, UserService } from '../../services/api'; // Still needed for CREATE (as it uses API backend for logic)
import { UserPlus, Save, Trash2, Search } from 'lucide-react';
import { useFirestoreCollection } from '../../hooks/useFirestoreCollection';
import { showSuccess, showError, showLoading, dismiss } from '../../context/FeedbackProvider';
import { orderBy, where } from 'firebase/firestore';
import { getFirestore, deleteDoc, doc } from 'firebase/firestore';

const UserManagement = () => {
  const { token } = useAuth();
  // Real-Time Data!
  // We order by createdAt if possible, or just default.
  const {
    data: users,
    loading: listLoading,
    error,
  } = useFirestoreCollection('users', [orderBy('createdAt', 'desc')]);

  const [formData, setFormData] = useState({
    firstName: '',
    lastName: '',
    internalNumber: '',
    ci: '',
    password: '',
    role: 'User',
    departmentId: '',
    jobRoleId: '',
  });

  const [submitting, setSubmitting] = useState(false);
  const [filter, setFilter] = useState('');

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setSubmitting(true);
    const toastId = showLoading('Guardando perfil en BD...');

    try {
      // 🛑 STRICT MODE: Use Direct Firestore Service
      // Note: This creates the Data Profile only.
      // The user cannot login until Auth credentials are created via Admin SDK or Cloud Function.
      await UserService.create(formData);

      dismiss(toastId);
      showSuccess('Perfil guardado correctamente (Ver en Nómina)');

      // Allow form reset
      setFormData({
        firstName: '',
        lastName: '',
        internalNumber: '',
        ci: '',
        password: '',
        role: 'User',
        departmentId: '',
        jobRoleId: '',
      });
    } catch (err: any) {
      dismiss(toastId);
      console.error(err);
      showError('Error al guardar: ' + err.message);
    } finally {
      setSubmitting(false);
    }
  };

  const handleDelete = async (id: string, name: string) => {
    if (!confirm(`¿Eliminar a ${name}?`)) return;

    // Optimistic UI handled by Firestore Hook update, but for Delete we can do it directly via DB SDK if allowed
    // or API. Assuming client delete permission for Admin.
    const toastId = showLoading('Eliminando...');
    try {
      const db = getFirestore();
      await deleteDoc(doc(db, 'users', id)); // Or 'personnel' if that's the collection
      // Hook will auto-remove it from list
      dismiss(toastId);
      showSuccess('Eliminado');
    } catch (e: any) {
      dismiss(toastId);
      showError('Error eliminando: ' + e.message);
    }
  };

  const filteredUsers = users.filter(
    (u: any) =>
      u.firstName?.toLowerCase().includes(filter.toLowerCase()) ||
      u.lastName?.toLowerCase().includes(filter.toLowerCase()) ||
      u.internalNumber?.includes(filter),
  );

  return (
    <div className="max-w-4xl mx-auto p-6 space-y-6">
      {/* Create Card */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl shadow-xl p-6">
        <div className="flex items-center gap-3 mb-6 border-b border-slate-800 pb-4">
          <div className="w-12 h-12 bg-indigo-600/20 rounded-full flex items-center justify-center">
            <UserPlus className="w-6 h-6 text-indigo-400" />
          </div>
          <div>
            <h2 className="text-xl font-bold text-white">Alta de Personal</h2>
            <p className="text-sm text-slate-400">Crear usuario y legajo vinculado.</p>
          </div>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm font-medium text-slate-400 mb-1 block">Nombre</label>
              <input
                className="input-field w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-white"
                required
                value={formData.firstName}
                onChange={(e) => setFormData({ ...formData, firstName: e.target.value })}
              />
            </div>
            <div>
              <label className="text-sm font-medium text-slate-400 mb-1 block">Apellido</label>
              <input
                className="input-field w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-white"
                value={formData.lastName}
                onChange={(e) => setFormData({ ...formData, lastName: e.target.value })}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm font-medium text-slate-400 mb-1 block">Cédula (CI)</label>
              <input
                className="input-field w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-white"
                placeholder="1.234.567-8"
                value={formData.ci}
                onChange={(e) => setFormData({ ...formData, ci: e.target.value })}
              />
            </div>
            <div>
              <label className="text-sm font-medium text-slate-400 mb-1 block">
                Nro Interno (Legajo)
              </label>
              <input
                className="input-field w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-white"
                required
                placeholder="1234"
                value={formData.internalNumber}
                onChange={(e) => setFormData({ ...formData, internalNumber: e.target.value })}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="text-sm font-medium text-slate-400 mb-1 block">Rol Sistema</label>
              <select
                className="input-field w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-white"
                value={formData.role}
                onChange={(e) => setFormData({ ...formData, role: e.target.value })}
              >
                <option value="User">Usuario / Chofer</option>
                <option value="Inspector">Inspector</option>
                <option value="Admin">Administrativo</option>
                <option value="SuperAdmin">Super Admin</option>
              </select>
            </div>
            <div>
              <label className="text-sm font-medium text-slate-400 mb-1 block">Contraseña</label>
              <input
                className="input-field w-full bg-slate-800 border border-slate-700 rounded-lg p-2 text-white"
                type="password"
                required
                value={formData.password}
                onChange={(e) => setFormData({ ...formData, password: e.target.value })}
              />
            </div>
          </div>

          <button
            disabled={submitting}
            className="w-full bg-indigo-600 hover:bg-indigo-500 text-white font-bold rounded-xl flex items-center justify-center gap-2 py-3 mt-6 transition-all"
          >
            {submitting ? (
              <span className="animate-spin rounded-full h-4 w-4 border-2 border-white/30 border-t-white"></span>
            ) : (
              <Save className="w-5 h-5" />
            )}
            Guardar Usuario
          </button>
        </form>
      </div>

      {/* List Card */}
      <div className="bg-slate-900 border border-slate-800 rounded-xl shadow-xl overflow-hidden">
        <div className="p-4 border-b border-slate-800 flex justify-between items-center bg-slate-800/50">
          <h3 className="font-bold text-white">Nómina ({filteredUsers.length})</h3>
          <div className="relative">
            <Search className="w-4 h-4 absolute left-3 top-1/2 -translate-y-1/2 text-slate-500" />
            <input
              value={filter}
              onChange={(e) => setFilter(e.target.value)}
              placeholder="Buscar..."
              className="bg-slate-900 border border-slate-700 rounded-lg pl-9 pr-3 py-1 text-sm text-white w-48 focus:w-64 transition-all"
            />
