                  className="w-full bg-slate-800 border border-slate-600 rounded-lg px-3 py-2 text-white text-sm"
                  required
                >
                  <option value="">— Servicio —</option>
                  {masterServicios.map((s) => (
                    <option key={s.servicioId} value={s.servicioId}>
