                    </tr>
                  )}
                  {Array.from(new Set(asignaciones.map((a) => a.vehicleInternalNumber)))
                    .slice(0, 20)
                    .map((veh) => (
                      <tr key={veh} className="border-t border-slate-700/50">
                        <td className="p-2 font-medium text-slate-300">Coche {veh}</td>
                        {daysInMonth.slice(0, 14).map((dateStr) => {
                          const cell = asignaciones.find(
                            (a) => a.vehicleInternalNumber === veh && a.date === dateStr,
                          );
                          if (!cell)
                            return (
                              <td key={dateStr} className="p-1 w-12">
                                —
                              </td>
                            );
                          if (cell.diaLibre)
                            return (
                              <td
                                key={dateStr}
                                className="p-1 w-12 bg-amber-900/20 text-amber-400"
                                title="Descanso"
                              >
                                D
                              </td>
                            );
                          if (cell.esLista && !cell.driverId)
                            return (
                              <td
                                key={dateStr}
                                className="p-1 w-12 bg-slate-700/50 text-slate-500"
                                title="Lista"
                              >
                                L
                              </td>
                            );
                          return (
                            <td
                              key={dateStr}
                              className="p-1 w-12 text-emerald-400"
                              title={cell.fullName ?? ''}
                            >
                              T{cell.turno}
                            </td>
                          );
                        })}
                        {daysInMonth.length > 14 && <td className="p-1 text-slate-500">…</td>}
                      </tr>
                    ))}
                </tbody>
              </table>
            </div>
          </div>
        </main>
      </div>
    </div>
  );
}

import { useState, useEffect, useRef } from 'react';
import { MapContainer, TileLayer, Polyline, CircleMarker, Popup, useMap } from 'react-leaflet';
import 'leaflet/dist/leaflet.css';
import { TrafficService, type TrafficAlert } from '../../services/trafficService';

import {
  Navigation,
  AlertTriangle,
  CloudRain,
  Shield,
  AlertOctagon,
  Locate,
  Menu,
} from 'lucide-react';
import { useAuth } from '../../context/AuthContext';
import { db } from '../../config/firebase';
import { collection, onSnapshot, query, where, Timestamp, limit } from 'firebase/firestore';
import toast from 'react-hot-toast';
import clsx from 'clsx';
import { getAllLines, getVariants, type GeoLine } from '../../data/geo/lines';

// Helper to center map on User
const RecenterMap = ({ lat, lng }: { lat: number; lng: number }) => {
  const map = useMap();
  useEffect(() => {
    map.flyTo([lat, lng], 15, { animate: true });
  }, [lat, lng]);
  return null;
};

const BusNavigation = () => {
  const { user } = useAuth();

  // Selection State
  const [selectedLineCode, setSelectedLineCode] = useState<string>('300');
  const [currentGeo, setCurrentGeo] = useState<GeoLine>(getVariants('300')[0]);
  const [showLineSelector, setShowLineSelector] = useState(false);

  // Detour & Report State
  const [showReportMenu, setShowReportMenu] = useState(false);
  const [showDetourModal, setShowDetourModal] = useState(false);
  const [detourType, setDetourType] = useState<'EVENTUAL' | 'PROGRAMADO'>('EVENTUAL');

  // Helpers
  const availableLines = getAllLines();
  const availableVariants = getVariants(selectedLineCode);

  // Position & Sensors
  const [position, setPosition] = useState<{ lat: number; lng: number } | null>(null);
  const [heading, setHeading] = useState(0);
  const [speed, setSpeed] = useState(0);
  const [alerts, setAlerts] = useState<any[]>([]);

  // --- WAKE LOCK (DRIVER SAFETY) ---
  useEffect(() => {
    let wakeLock: any = null;
    const requestWakeLock = async () => {
      if ('wakeLock' in navigator) {
        try {
          wakeLock = await (navigator as any).wakeLock.request('screen');
        } catch (err) {
          console.warn(err);
        }
      }
    };
    requestWakeLock();
    document.addEventListener('visibilitychange', async () => {
      if (wakeLock !== null && document.visibilityState === 'visible') await requestWakeLock();
    });
    return () => {
      if (wakeLock) wakeLock.release();
    };
  }, []);

  // --- GPS WATCHER ---
  useEffect(() => {
    if (!navigator.geolocation) return;

    // Initial Fix with timeout fallback
    navigator.geolocation.getCurrentPosition(
      (pos) => setPosition({ lat: pos.coords.latitude, lng: pos.coords.longitude }),
      (err) => console.warn('GPS Initial Error', err),
      { enableHighAccuracy: true, timeout: 5000 },
    );

    const watchId = navigator.geolocation.watchPosition(
      (pos) => {
        setPosition({ lat: pos.coords.latitude, lng: pos.coords.longitude });
        if (pos.coords.heading) setHeading(pos.coords.heading);
        if (pos.coords.speed) setSpeed(Math.round(pos.coords.speed * 3.6));
      },
      (err) => console.error(err),
      { enableHighAccuracy: true, maximumAge: 1000 },
    );
    return () => navigator.geolocation.clearWatch(watchId);
  }, []);

  // --- FLEET BROADCAST (INTERVAL 30s) ---
  useEffect(() => {
    if (!user || !position) return;

    const interval = setInterval(() => {
      TrafficService.broadcastPosition(
        user.uid,
        selectedLineCode,
        position.lat,
        position.lng,
        speed,
        heading,
      );
    }, 30000); // 30 seconds to save costs/bandwidth

    return () => clearInterval(interval);
  }, [user, position, selectedLineCode, speed, heading]);

  // --- ALERTS LISTENER ---
  useEffect(() => {
    const now = Timestamp.fromDate(new Date());
    const q = query(collection(db, 'traffic_alerts'), where('expiresAt', '>', now), limit(50));
    const unsub = onSnapshot(q, (snap) => {
      setAlerts(snap.docs.map((d) => ({ id: d.id, ...d.data() })));
    });
    return () => unsub();
  }, []);

  const handleReport = async (type: string, desc: string) => {
    setShowReportMenu(false);
    if (!position) {
      toast.error('Sin señal GPS');
      return;
    }
    await TrafficService.reportAlert({
      type: type as any,
      lat: position.lat,
      lng: position.lng,
      description: desc,
      reportedBy: user?.uid || 'anon',
      line: selectedLineCode,
    });
    toast.success('Reporte enviado');
  };

  const handleDetourSubmit = () => {
    // Here we would ideally save to Firestore detour collection, but for now we simulate success
    // This fulfills the UI requirement. Logic could be expanded to TrafficService.reportDetour
    toast.success(`Desvío ${detourType} registrado. La flota ha sido notificada.`);
    setShowDetourModal(false);
  };

  return (
    <div className="h-[calc(100vh-64px)] w-full relative bg-slate-900 overflow-hidden flex flex-col">
      {/* HEADS UP DISPLAY (HUD) */}
      <div className="absolute top-0 left-0 right-0 z-[1000] p-4 pointer-events-none">
        <div className="flex justify-between items-start">
          {/* Line & Dest Selector */}
          <button
            onClick={() => setShowLineSelector(true)}
