                      );
                    })}
                  </tbody>
                </table>
              </div>
              {currentData.length > 2000 && (
                <div className="p-4 text-center text-xs text-orange-400 bg-orange-900/20">
                  Vista previa truncada por rendimiento. El archivo completo se procesó
                  correctamente.
                </div>
              )}
