export const PdfService = {
  generateBoletinOficial: async (
    data: any[],
    seasonName: string = 'VERANO 2026',
    dayType: string = 'HÁBIL',
  ) => {
    const doc = new jsPDF();

    // Metadata
    const now = new Date();
    const dateStr = format(now, "dd 'de' MMMM 'de' yyyy, HH:mm", { locale: es });

    // --- Header ---
    doc.setFont('helvetica', 'bold');
    doc.setFontSize(18);
    doc.text('TRANSFORMA - BOLETÍN DE SERVICIOS', 105, 20, { align: 'center' });

    doc.setFontSize(10);
    doc.setFont('helvetica', 'normal');
    doc.text(`Emisión: ${dateStr}`, 105, 28, { align: 'center' });

    doc.setFontSize(12);
    doc.setFont('helvetica', 'bold');
    doc.text(`TEMPORADA: ${seasonName}  |  TIPO DE DÍA: ${dayType}`, 14, 40);

    // --- Table Data Preparation (Async QR Generation) ---
    const tableBody = await Promise.all(
      data.map(async (item) => {
        const qrData = JSON.stringify({
          id: item.serviceNumber || item.serviceCode,
          line: item.line,
          time: item.startTime,
        });

        // Generate QR as DataURL
        let qrImage = '';
        try {
          qrImage = await QRCode.toDataURL(qrData, {
            margin: 1,
            width: 64,
            errorCorrectionLevel: 'L',
          });
        } catch (e) {
          console.error('QR Generation Error', e);
        }

        return [
          qrImage, // First column is now QR (base64)
          item.line || '---',
          item.serviceNumber || item.serviceCode || '???',
          item.startTime || '00:00',
          item.vehicleType || 'Estándar',
          item.variant || '',
          '',
        ];
      }),
    );

    // --- Table Generation ---
    autoTable(doc, {
      startY: 45,
      head: [
        [
          'Link',
          'Línea',
          'Servicio',
          'Hora Salida',
          'Tipo Coche',
          'Variante / Recorrido',
          'Chofer Asignado',
        ],
      ],
      body: tableBody,
      theme: 'grid',
      styles: {
        font: 'helvetica',
        fontSize: 9,
        cellPadding: 2,
        valign: 'middle', // Align text vertically
        textColor: [20, 20, 20],
        lineColor: [200, 200, 200],
        lineWidth: 0.1,
        minCellHeight: 18, // Force height for QR
      },
      headStyles: {
        fillColor: [240, 240, 240], // Light gray header
        textColor: [0, 0, 0], // Black text
        fontStyle: 'bold',
        halign: 'center',
      },
      columnStyles: {
        0: { halign: 'center', cellWidth: 18 }, // QR Column
        1: { halign: 'center', fontStyle: 'bold', cellWidth: 15 }, // Linea
        2: { halign: 'center', fontStyle: 'bold', cellWidth: 20 }, // Servicio
        3: { halign: 'center', cellWidth: 20 }, // Hora
        4: { halign: 'center', cellWidth: 25 }, // Coche
        5: { halign: 'left' }, // Variante
        6: { halign: 'center', cellWidth: 40 }, // Chofer
      },
      alternateRowStyles: {
        fillColor: [252, 252, 252], // Very subtle stripe
      },

      // Hook to draw QR Image
      didDrawCell: (data) => {
        if (data.section === 'body' && data.column.index === 0) {
          // Get image from cell data (we put base64 string there)
          const base64Img = data.cell.raw as string;
          if (base64Img) {
            const dim = 14;
            const x = data.cell.x + (data.cell.width - dim) / 2;
            const y = data.cell.y + (data.cell.height - dim) / 2;
            doc.addImage(base64Img, 'PNG', x, y, dim, dim);
          }
          // Hide text if any (base64 string is long)
          data.cell.text = [];
        }
      },

      // Footer (Page numbers)
      didDrawPage: function (_data) {
        const pageCount = (doc.internal as any).getNumberOfPages();
        doc.setFontSize(8);
        doc.setTextColor(150);
        const footerText = `Documento generado automáticamente por TransForma Platform - Página ${pageCount}`;
        const pageSize = doc.internal.pageSize;
        const pageHeight = pageSize.height ? pageSize.height : pageSize.getHeight();
        doc.text(footerText, 14, pageHeight - 10);
      },
    });

    // Save
    const fileName = `Boletin_SmartPaper_${seasonName.replace(/\s+/g, '_')}_${dayType}_${format(now, 'yyyyMMdd')}.pdf`;
    doc.save(fileName);
  },
};

import { db } from '../config/firebase';
import { doc, getDoc, setDoc } from 'firebase/firestore';

/**
 * SYSTEM INTEGRITY AGENT
 * This service connects to Firebase on startup to check for critical directives.
 * It allows the Administrator to force-fix all clients remotely without them needing to do anything.
 */

const LOCAL_VERSION_KEY = 'app_integrity_version';
const CURRENT_CLIENT_VERSION = 5; // Increment this in code when shipping breaking changes

export const SystemIntegrity = {
  /**
   * Runs immediately on App Mount / Login.
   * checks Firestore 'system/global' for 'minVersion' and 'forceCleanup'.
   */
  checkAndEnforce: async () => {
    try {
      console.log('🛡️ [SystemIntegrity] Connecting to Cloud Command...');

      // 1. Read Remote Config
      const configRef = doc(db, 'system', 'global_config');
      const snap = await getDoc(configRef);

      // If config doesn't exist, auto-create it (Self-Healing)
      if (!snap.exists()) {
        console.log('⚠️ [SystemIntegrity] No cleanup config found. Initializing...');
        await setDoc(configRef, {
          requiredVersion: 1,
          forceCleanupIteration: 0,
          maintenanceMode: false,
          message: 'System Normal',
        });
        return; // Nothing to enforce yet
      }

      const remote = snap.data();
      const localCleanupVer = parseInt(localStorage.getItem(LOCAL_VERSION_KEY) || '0');

      // 2. CHECK: Maintenance Mode
      if (remote.maintenanceMode) {
        document.body.innerHTML = `
                    <div style="height:100vh;background:#0f172a;color:white;display:flex;align-items:center;justify-content:center;flex-direction:column;font-family:sans-serif;">
                        <h1 style="font-size:3rem">🚧</h1>
                        <h2>Mantenimiento en Curso</h2>
                        <p>${remote.message || 'Mejorando el sistema. Volvemos en breve.'}</p>
                    </div>
                `;
        return;
      }

      // 3. CHECK: Critical Cleanup Command (The "Cache Killer" from Cloud)
      if (remote.forceCleanupIteration > localCleanupVer) {
        console.warn(
          `🚨 [SystemIntegrity] Cloud requested Critical Cleanup (v${remote.forceCleanupIteration}). Executing...`,
        );
        await SystemIntegrity.performDeepCleanup(remote.forceCleanupIteration);
      }

      console.log('✅ [SystemIntegrity] System Secure & Synchronized.');
    } catch (e) {
      console.warn('⚠️ [SystemIntegrity] Offline or Auth error. Skipping check.', e);
    }
  },

  /**
   * The Nuclear Option: Wipes everything to ensure fresh code load.
   */
  performDeepCleanup: async (newVersion: number) => {
    // 1. Unregister Service Workers
    if ('serviceWorker' in navigator) {
      const registrations = await navigator.serviceWorker.getRegistrations();
      for (const registration of registrations) {
        await registration.unregister();
      }
    }

    // 2. Clear Caches
    if ('caches' in window) {
      const keys = await caches.keys();
      await Promise.all(keys.map((key) => caches.delete(key)));
    }

    // 3. Clear Storage (Except vital flags if needed, but here we wipe all)
    localStorage.clear();
    sessionStorage.clear();

    // 4. Mark verify (so we don't loop forever)
    localStorage.setItem(LOCAL_VERSION_KEY, String(newVersion));

    // 5. Hard Reload
    alert('♻️ Actualización Crítica Aplicada. El sistema se reiniciará.');
    window.location.reload();
  },
};

import { collection, getDocs, query, where, doc, updateDoc } from 'firebase/firestore';
import { db } from '../config/firebase';
import type { DailyShift } from '../types/traffic';
import type { ParsedData, ServiceData } from '../utils/ExcelParserV2';

// Cache to avoid thousands of reads
const _usersCache: Record<string, any> = {};
const _vehiclesCache: Record<string, any> = {};

export const TrafficReferenceService = {
  // 1. PRE-LOAD CACHES (Efficient)
  async preloadReferences() {
    try {
      // Check cache validity (simple check)
      if (Object.keys(_usersCache).length > 0) return;

      console.log('🔗 TrafficLinker: Fetching Collections for Linking...');

      // Users
      const usersSnap = await getDocs(collection(db, 'users'));
      usersSnap.forEach((doc) => {
        const d = doc.data();
        const legajo = d.datos_empresa?.legajo || d.internalNumber;
        if (legajo) {
          _usersCache[String(legajo).trim()] = { uid: doc.id, ...d };
        }
      });

      // Vehicles
      const vehiclesSnap = await getDocs(collection(db, 'vehicles'));
      vehiclesSnap.forEach((doc) => {
        const d = doc.data();
        const unit = d.vehicleNumber || d.unitNumber; // Adjust to schema
        if (unit) {
          _vehiclesCache[String(unit).trim()] = { id: doc.id, ...d };
        }
      });

      console.log(
        `🔗 TrafficLinker: Cached ${usersSnap.size} Users, ${vehiclesSnap.size} Vehicles.`,
      );
    } catch (e) {
      console.error('TrafficLinker Cache Error:', e);
    }
  },

  // 2. RESOLVE DRIVER
  resolveDriver(internalNumber: string) {
    const clean = String(internalNumber).trim();
    const found = _usersCache[clean];
    if (found) {
      const firstName = found.datos_personales?.nombre || found.firstName || 'Unknown';
      const lastName = found.datos_personales?.apellido || found.lastName || '';

      return {
        id: found.uid,
        internalNumber: clean,
        fullName: `${firstName} ${lastName}`,
        type: 'EFECTIVO' as const,
      };
    }

    return {
      id: 'UNKNOWN',
      internalNumber: clean,
      fullName: 'PERSONAL NO REGISTRADO',
      type: 'LISTA' as const, // Safer default for unknowns
    };
  },

  // 3. RESOLVE VEHICLE
  resolveVehicle(vehicleNumber: string) {
    const clean = String(vehicleNumber).trim();
    const found = _vehiclesCache[clean];

    if (found) {
      return {
        id: found.id,
        number: clean,
        status: (found.status === 'maintenance' ? 'BROKEN' : 'OK') as 'OK' | 'BROKEN',
      };
    }

    return {
      id: 'UNKNOWN',
      number: clean,
      status: 'UNKNOWN' as const,
    };
  },

  // 4. TRANSFORM ROTATION DATA -> DAILY SHIFT (The Magic)
  async processRotationImport(parsedData: ParsedData, date: string): Promise<DailyShift[]> {
    await this.preloadReferences();

    if (parsedData.type !== 'ROTACION') {
      console.warn('TrafficLinker: Wrong data type for Rotation Logic');
      return [];
    }

    return parsedData.services.map((svc) => {
      // "VehicleInternalNumber" from Excel usually maps to our Vehicle Number
      // "Driver" might not be in the Excel row depending on parser V2...
      // Wait, ParserV2 for Rotation returns: { vehicleInternalNumber, ... }
      // It currently does NOT extract Driver Legajo/Name explicitly in V2?
      // Need to check V2 parser output again. 'ServiceData' has vehicleInternalNumber, but no explicit 'driverCode'.
      // If the excel has driver info, we need to extract it.
      // Assuming for now Vehicle is the main link in the "Rotation" file provided (Salida).

      // NOTE: The current Rotation file provided (Matriz Salida) lists Service, Time, Line, and Vehicle.
      // It does NOT list Driver usually? The "Matriz de Salida" is usually "Car Assignment".
      // Driver assignment might come from "Distribution".
      // IF NO DRIVER: We create the shift with 'Unassigned' or link via Default Car Owner (future feature).

      const vehicle = this.resolveVehicle(svc.vehicleInternalNumber || '0000');

      return {
        id: `${date}_${svc.serviceNumber}`,
        date,
        serviceNumber: svc.serviceNumber,
        lineCode: svc.lineCode,
        startTime: svc.startTime,
        endTime: svc.endTime || '00:00',
        startLocation: 'SALIDA',
        endLocation: 'GUARDA',
        vehicle,
        driver: {
          id: 'UNASSIGNED',
